mapper.select:
SELECT id, account_code, account_name, account_type, account_subtype, is_debit_normal, parent_account_id, is_active, display_order, created_at, updated_at FROM chart_of_accounts WHERE account_type = #{accountType}
AND account_subtype = #{accountSubtype}
AND is_active = true ORDER BY display_order, account_code

SELECT id, account_code, account_name, account_type, account_subtype, is_debit_normal, parent_account_id, is_active, display_order, created_at, updated_at FROM chart_of_accounts WHERE is_active = true
AND ( account_code ILIKE '%' || #{keyword} || '%' OR account_name ILIKE '%' || #{keyword} || '%' )
AND account_type = #{accountType}
ORDER BY display_order, account_code LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM chart_of_accounts WHERE is_active = true
AND ( account_code ILIKE '%' || #{keyword} || '%' OR account_name ILIKE '%' || #{keyword} || '%' )
AND account_type = #{accountType}

mapper.insert:
INSERT INTO chart_of_accounts (
    account_code, account_name, account_type, account_subtype,
    is_debit_normal, parent_account_id, is_active, display_order
) VALUES (
    #{accountCode}, #{accountName}, #{accountType}::account_type_enum, #{accountSubtype},
    #{isDebitNormal}, #{parentAccountId}, #{isActive}, #{displayOrder}
)

mapper.select:
SELECT CASE WHEN COUNT(*) > 0 THEN true ELSE false END
FROM chart_of_accounts
WHERE account_code = #{accountCode}

SELECT CASE WHEN COUNT(*) > 0 THEN true ELSE false END
FROM journal_entry_details
WHERE account_code = #{accountCode}

WITH RECURSIVE account_hierarchy AS ( -- 기준 계정 SELECT id, account_code, account_name, account_type, account_subtype, is_debit_normal, parent_account_id, is_active, display_order, created_at, updated_at, 0 as level FROM chart_of_accounts WHERE id = #{accountId}
UNION ALL
-- 하위 계정들 SELECT coa.id, coa.account_code, coa.account_name, coa.account_type, coa.account_subtype, coa.is_debit_normal, coa.parent_account_id, coa.is_active, coa.display_order, coa.created_at, coa.updated_at, ah.level + 1 FROM chart_of_accounts coa INNER JOIN account_hierarchy ah ON coa.parent_account_id = ah.id WHERE coa.is_active = true ) SELECT id, account_code, account_name, account_type, account_subtype, is_debit_normal, parent_account_id, is_active, display_order, created_at, updated_at FROM account_hierarchy ORDER BY level, display_order, account_code

SELECT COALESCE(MAX(display_order), 0)
FROM chart_of_accounts

    WHERE account_type = #{accountType}
